export const getPremiumPricingText = (languageCode?: string) => {
  const language = premiumPricingLanguages.includes(languageCode as PremiumPricingLanguage)
    ? (languageCode as PremiumPricingLanguage)
    : 'en';

  return premiumPricingText[language] ?? premiumPricingText.en;
};

export type PremiumPricingText = ReturnType<typeof getPremiumPricingText>;
